# helper function to generate and verify tokens
def get_token(app):
    SECRET_KEY = app.config['SECRET']
    expires = dt.datetime.utcnow() + dt.timedelta(days=7)
    
    serializer = Serializer(SECRET_KEY)
    data = {
        'name':  request.form.get('username'),
        'exp': datetime.utcnow() + dt.timedelta(days=20), # the token will expire after 1 day
    }

    token = serializer.dumps(data, salt=app.config['SALT'])
    return token

def verify_token(token):
    SECRET_KEY = app.config['SECRET']    
    serializer = Serializer(SECRET_KEY)
    data = serializer.loads(token, max_age=20 * 60) # the token will expire after 1 day
    
    return data

